+        let action = c.tick_at(apply_time);
+        assert!(
+            matches!(action, CoalesceAction::ApplyResize { width: 100, height: 40, .. }),
+            "expected ApplyResize(100, 40), got {action:?}"
+        );
+        assert_eq!(c.last_applied(), (100, 40));
+    }
